// One-shot: create the community platform schema.
//
//   CommunityProfile      — 1:1 with IdentityUser. Handle, bio, tone,
//                           cover image, public visibility. This is the
//                           source of truth for /u/[handle] pages.
//   CommunityPost         — the feed unit. Kinds mirror studentunion-v2:
//                             win · tip · showcase · ask · milestone
//                           `source` distinguishes user-composed posts
//                           from auto-generated ones (grand-test pass,
//                           badge earned, cohort complete) so the UI
//                           can render them differently.
//   CommunityPostReaction — like OR save. One row per (postId, userId,
//                           kind). Counted into CommunityPost.likeCount
//                           via a small denorm.
//   CommunityPostComment  — one comment per row. commentCount denormed
//                           to CommunityPost for O(1) reads on tiles.
//   CommunityFollow       — one row per (followerId, followedId).
//                           Follower and followee counts denormed to
//                           CommunityProfile.
//
// Follows the raw-SQL convention already used by add-blog-tables.mjs
// so the community-context repositories can read via prisma.$queryRaw
// without waiting on a Prisma generate cycle.
//
// Run locally:  cd packages/db && node scripts/add-community-tables.mjs

import { readFileSync } from 'node:fs'
import { dirname, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

const __d = dirname(fileURLToPath(import.meta.url))
for (const line of readFileSync(resolve(__d, '../.env'), 'utf8').split('\n')) {
  const m = /^([A-Z0-9_]+)=(.*)$/.exec(line.trim())
  if (m && !process.env[m[1]]) process.env[m[1]] = m[2].replace(/^"|"$/g, '')
}
const { PrismaClient } = await import('@prisma/client')
const p = new PrismaClient()

// ── CommunityProfile ─────────────────────────────────────────
// `handle` is what appears in the /u/[handle] URL — kebab-case-ish,
// unique. `tone` is one of the accent palette values we already use
// on the marketing site so profiles feel branded without extra CSS.
// `publicVisibility` gates whether the profile page is server-rendered
// as public (SEO on) or requires auth to view.
await p.$executeRawUnsafe(`
  CREATE TABLE IF NOT EXISTS "CommunityProfile" (
    "id" TEXT PRIMARY KEY,
    "userId" TEXT UNIQUE NOT NULL,
    "handle" TEXT UNIQUE NOT NULL,
    "handleEditsRemaining" INTEGER NOT NULL DEFAULT 1,
    "bio" TEXT,
    "coverImageUrl" TEXT,
    "tone" TEXT NOT NULL DEFAULT 'accent'
      CHECK ("tone" IN ('accent', 'brand', 'grape', 'coral', 'mint', 'blush', 'ink')),
    "verified" BOOLEAN NOT NULL DEFAULT FALSE,
    "publicVisibility" TEXT NOT NULL DEFAULT 'public'
      CHECK ("publicVisibility" IN ('public', 'members', 'hidden')),
    "followerCount" INTEGER NOT NULL DEFAULT 0,
    "followingCount" INTEGER NOT NULL DEFAULT 0,
    "postCount" INTEGER NOT NULL DEFAULT 0,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT NOW(),
    "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT NOW()
  )
`)
await p.$executeRawUnsafe(`
  CREATE INDEX IF NOT EXISTS "CommunityProfile_userId_idx"
    ON "CommunityProfile" ("userId")
`)
// Case-insensitive uniqueness on handle so @Ibrahim and @ibrahim
// can't both exist. Lookups do WHERE lower(handle) = ..., so this
// index also serves as the read index.
await p.$executeRawUnsafe(`
  CREATE UNIQUE INDEX IF NOT EXISTS "CommunityProfile_handle_lower_idx"
    ON "CommunityProfile" (lower("handle"))
`)

// ── CommunityPost ────────────────────────────────────────────
// `source`:
//   'composed' — user typed it into the composer
//   'auto:grand-test-pass' — generated by AssessmentAttempt hook
//   'auto:cohort-complete'
//   'auto:badge-earned'
// `linkedEntityType/Id` — points back to the achievement (attempt,
// enrollment, certificate) so we can render richer cards + verify
// authenticity without duplicating the data.
await p.$executeRawUnsafe(`
  CREATE TABLE IF NOT EXISTS "CommunityPost" (
    "id" TEXT PRIMARY KEY,
    "authorId" TEXT NOT NULL,
    "kind" TEXT NOT NULL
      CHECK ("kind" IN ('win', 'tip', 'showcase', 'ask', 'milestone')),
    "body" TEXT NOT NULL,
    "tags" TEXT[] NOT NULL DEFAULT '{}',
    "mediaUrl" TEXT,
    "source" TEXT NOT NULL DEFAULT 'composed',
    "linkedEntityType" TEXT,
    "linkedEntityId" TEXT,
    "likeCount" INTEGER NOT NULL DEFAULT 0,
    "commentCount" INTEGER NOT NULL DEFAULT 0,
    "publishedAt" TIMESTAMP(3) NOT NULL DEFAULT NOW(),
    "deletedAt" TIMESTAMP(3),
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT NOW(),
    "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT NOW()
  )
`)
await p.$executeRawUnsafe(`
  CREATE INDEX IF NOT EXISTS "CommunityPost_authorId_publishedAt_idx"
    ON "CommunityPost" ("authorId", "publishedAt" DESC)
    WHERE "deletedAt" IS NULL
`)
await p.$executeRawUnsafe(`
  CREATE INDEX IF NOT EXISTS "CommunityPost_publishedAt_idx"
    ON "CommunityPost" ("publishedAt" DESC)
    WHERE "deletedAt" IS NULL
`)
// Partial UNIQUE prevents the grand-test-pass auto-post from firing
// twice if the hook retries. One post per (source, linkedEntityId).
await p.$executeRawUnsafe(`
  CREATE UNIQUE INDEX IF NOT EXISTS "CommunityPost_source_linkedEntity_unique_idx"
    ON "CommunityPost" ("source", "linkedEntityId")
    WHERE "linkedEntityId" IS NOT NULL AND "source" LIKE 'auto:%'
`)

// ── CommunityPostReaction ────────────────────────────────────
await p.$executeRawUnsafe(`
  CREATE TABLE IF NOT EXISTS "CommunityPostReaction" (
    "id" TEXT PRIMARY KEY,
    "postId" TEXT NOT NULL,
    "userId" TEXT NOT NULL,
    "kind" TEXT NOT NULL
      CHECK ("kind" IN ('like', 'save')),
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT NOW()
  )
`)
await p.$executeRawUnsafe(`
  CREATE UNIQUE INDEX IF NOT EXISTS "CommunityPostReaction_post_user_kind_idx"
    ON "CommunityPostReaction" ("postId", "userId", "kind")
`)
await p.$executeRawUnsafe(`
  CREATE INDEX IF NOT EXISTS "CommunityPostReaction_userId_kind_idx"
    ON "CommunityPostReaction" ("userId", "kind", "createdAt" DESC)
`)

// ── CommunityPostComment ─────────────────────────────────────
await p.$executeRawUnsafe(`
  CREATE TABLE IF NOT EXISTS "CommunityPostComment" (
    "id" TEXT PRIMARY KEY,
    "postId" TEXT NOT NULL,
    "authorId" TEXT NOT NULL,
    "body" TEXT NOT NULL,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT NOW(),
    "deletedAt" TIMESTAMP(3)
  )
`)
await p.$executeRawUnsafe(`
  CREATE INDEX IF NOT EXISTS "CommunityPostComment_postId_createdAt_idx"
    ON "CommunityPostComment" ("postId", "createdAt" ASC)
    WHERE "deletedAt" IS NULL
`)

// ── CommunityFollow ──────────────────────────────────────────
// followerId follows followedId. Self-follows blocked at the app layer,
// but the CHECK enforces it in the DB too so a race can't sneak one in.
await p.$executeRawUnsafe(`
  CREATE TABLE IF NOT EXISTS "CommunityFollow" (
    "id" TEXT PRIMARY KEY,
    "followerId" TEXT NOT NULL,
    "followedId" TEXT NOT NULL,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT NOW(),
    CHECK ("followerId" <> "followedId")
  )
`)
await p.$executeRawUnsafe(`
  CREATE UNIQUE INDEX IF NOT EXISTS "CommunityFollow_pair_idx"
    ON "CommunityFollow" ("followerId", "followedId")
`)
await p.$executeRawUnsafe(`
  CREATE INDEX IF NOT EXISTS "CommunityFollow_followedId_idx"
    ON "CommunityFollow" ("followedId", "createdAt" DESC)
`)

console.log('[add-community-tables] all community tables ready')
await p.$disconnect()
